However, this same code compiled with C++14 and later breaks because, with C++14 and later, only compile-time string operations are allowed inside the body of the ``_()`` call (or at least that's my understanding while skimming the code).

Would it be possible to have runtime string manipulation capabilities in C++14/17 as well?

A const object returned by a function should not be mutable from Python. Currently this is not the case if the function / method returns a `shared_ptr<const T>`.
Specifically, changing the attribute `.value` should not be allowed on an object returned by `.get_const()` in the following example, but it is.

    #include <pybind11/pybind11.h>
    
    class Test {
    public:
        explicit Test(int v) : value{v} {};
        int value {};
    
        std::shared_ptr<Test const> get_const() {
            static std::shared_ptr<Test const> instance(new Test(1));
            return instance;
        }
    };
    
    namespace py = pybind11;
    
    PYBIND11_DECLARE_HOLDER_TYPE(T, std::shared_ptr<T>);
    
    PYBIND11_PLUGIN(const_test) {
        py::module m("const_test");
    
        py::class_<Test, std::shared_ptr<Test>>(m, "Test")
            .def(py::init<int>())
            .def("get_const", &Test::get_const)
            .def_readwrite("value", &Test::value);
    
        return m.ptr();
    }
